+  if (serialized.includes('bearer') || serialized.includes('authorization')) return 'bearer';
+  if (serialized.includes('oauth')) return 'oauth2';
+  if (serialized.includes('api_key') || serialized.includes('apikey')) return 'api_key';
+  return 'none';
