+    const k = Math.min(3, Math.max(1, points.length));
+    let centroids = points.slice(0, k).map((point) => ({ x: point.x, y: point.y }));
+    for (let iter = 0; iter < 5; iter++) {
+      const buckets: ClusterPoint[][] = Array.from({ length: k }, () => []);
+      for (const point of points) {
+        let best = 0;
+        let bestDist = Number.POSITIVE_INFINITY;
+        centroids.forEach((centroid, idx) => {
+          const distance = Math.hypot(point.x - centroid.x, point.y - centroid.y);
+          if (distance < bestDist) {
+            bestDist = distance;
+            best = idx;
+          }
+        });
+        buckets[best].push(point);
+      }
+      centroids = buckets.map((bucket, idx) => {
+        if (!bucket.length) {
+          return centroids[idx];
+        }
+        return {
+          x: bucket.reduce((acc, point) => acc + point.x, 0) / bucket.length,
+          y: bucket.reduce((acc, point) => acc + point.y, 0) / bucket.length,
+        };
+      });
+    }
+
+    const clusters = points.map((point) => {
